export default function createObject(proto, props) {
  const validProto = proto === null || typeof proto === 'object' || typeof proto === 'function';
  if (!validProto) throw new TypeError('proto must be an object or null');

  const obj = Object.create(proto);
  if (props != null) {
    if (typeof props !== 'object') throw new TypeError('props must be an object');
    Object.assign(obj, props);
  }
  return obj;
}
